self.addEventListener("install",function(t){t.waitUntil(caches.open("my-cache").then(function(t){return Promise.all(["favicon.ico","img/android-chrome-192x192.png","img/android-chrome-512x512.png","img/apple-touch-icon.png","img/favicon-16x16.png","img/favicon-32x32.png","img/text128.png","img/text144.png","img/text152.png","img/text192.png","img/text384.png","img/text512.png","img/text72.png","img/text96.png","js/vkbeautify.min.js","manifest.json","js/app.min.js","css/editor.min.css"].map(function(n){return fetch(n).then(function(e){return t.put(n,e)}).catch(function(t){console.warn("Failed to cache "+n,t)})}))}))}),self.addEventListener("fetch",function(t){t.request.url.startsWith("chrome-extension://")||t.respondWith(fetch(t.request).then(function(n){if(!n||200!==n.status||"basic"!==n.type)return n;var e=n.clone();return caches.open("my-cache").then(function(n){t.request.url.match("^(http|https)://")&&n.put(t.request,e)}),n}).catch(function(){return caches.match(t.request)}))});